final ctx = DataCaptureContext.forLicenseKey(kScanditKey);
final cam = Camera.defaultCamera!;
await cam.applySettings(BarcodeCapture.recommendedCameraSettings);
ctx.setFrameSource(cam);
final capture = BarcodeCapture(ctx, BarcodeCaptureSettings()
  ..enableSymbologies({Symbology.ean13, Symbology.qr}));
capture.addListener(...);   // frames of decoded barcodes
cam.switchToDesiredState(FrameSourceState.on);
